external_knowledge:
Recently failed tasks refer to tasks that have a status of 'failed' and the time between their failure and now is less than or equal to 1 week (604800 seconds).;
Configurations refer to the task parameters in the context of task information.;
Departments are entities within an organization responsible for initiating tasks.;

sql:
SELECT task_name, task_hash, verbose_name 
FROM tasks 
WHERE retry_count = (SELECT MAX(retry_count) FROM tasks);

SELECT t.task_name, t.status, t.execution_time
FROM tasks t
WHERE t.id IN (
    SELECT td.task_id
    FROM task_dependencies td
);

SELECT verbose_name, retry_count AS failed_attempts
FROM tasks
WHERE retry_count > 3;

SELECT id, task_name, retry_count
FROM tasks
WHERE retry_count > (
    SELECT AVG(retry_count)
    FROM tasks
);

SELECT tasks.task_name, tasks.priority, tasks.department, tasks.status
FROM tasks
WHERE tasks.status = 'running' OR tasks.status = 'failed';

SELECT id, task_name, execution_time, status
FROM tasks
WHERE execution_time > (SELECT AVG(execution_time) FROM tasks);

